String appreciation(double moyenne) {
  if (moyenne >= 16) return 'Excellent';
  if (moyenne >= 12) return 'Assez bien';
  if (moyenne >= 10) return 'Passable';
  return 'Insuffisant';
}

bulletin.forEach((nom, notes) {
